example.code:
from pydantic import BaseModel, Field from typing import List
class Entity(BaseModel): name: str = Field(description="Entity name as it appears in the text") type: str = Field(description="Entity type: person, company, location, or product") confidence: float = Field(ge=0, le=1, description="Confidence score 0.0-1.0")
class ExtractionResult(BaseModel): entities: List[Entity] summary: str = Field(description="One sentence summary of the text") language: str = Field(description="ISO 639-1 language code, e.g., 'en'")
